INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Seated_Palms-Down_Barbell_Wrist_Curl','Seated Palms-Down Barbell Wrist Curl','antebrazos',ARRAY[]::text[],'barra','strength',ARRAY['Hold a barbell with both hands and your palms facing down; hands spaced about shoulder width.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your forearms on top of your upper thighs with your palms down. Tip: Make sure that the back of the wrists lay on top of your knees. This will be your starting position.','Lower the bar as far as possible while inhaling and keeping a tight grip.','Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move.'],'Hold a barbell with both hands and your palms facing down; hands spaced about shoulder width. Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart. Lean forward and place your forearms on top of your upper thighs with your palms down. Tip: Make sure that the back of the wrists lay on top of your knees. This will be your starting position. Lower the bar as far as possible while inhaling and keeping a tight grip. Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Palms-Down_Barbell_Wrist_Curl/0.jpg','exercisedb',true),('Seated_Side_Lateral_Raise','Seated Side Lateral Raise','hombros',ARRAY[]::text[],'mancuernas','strength',ARRAY['Pick a couple of dumbbells and sit at the end of a flat bench with your feet firmly on the floor. Hold the dumbbells with your palms facing in and your arms straight down at your sides at arms'''' length. This will be your starting position.','While maintaining the torso stationary (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.','Lower the dumbbells back down slowly to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'],'Pick a couple of dumbbells and sit at the end of a flat bench with your feet firmly on the floor. Hold the dumbbells with your palms facing in and your arms straight down at your sides at arms'' length. This will be your starting position. While maintaining the torso stationary (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top. Lower the dumbbells back down slowly to the starting position as you inhale. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Side_Lateral_Raise/0.jpg','exercisedb',true),('Seated_Triceps_Press','Seated Triceps Press','tríceps',ARRAY[]::text[],'mancuernas','strength',ARRAY['Sit down on a bench with back support and grasp a dumbbell with both hands and hold it overhead at arm''''s length. Tip: a better way is to have somebody hand it to you especially if it is very heavy. The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hand should be facing inward. This will be your starting position.','Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semi-circular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.','Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.','Repeat for the recommended amount of repetitions.'],'Sit down on a bench with back support and grasp a dumbbell with both hands and hold it overhead at arm''s length. Tip: a better way is to have somebody hand it to you especially if it is very heavy. The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hand should be facing inward. This will be your starting position. Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semi-circular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step. Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Triceps_Press/0.jpg','exercisedb',true),('Seated_Two-Arm_Palms-Up_Low-Pulley_Wrist_Curl','Seated Two-Arm Palms-Up Low-Pulley Wrist Curl','antebrazos',ARRAY[]::text[],'cable','strength',ARRAY['Put a bench in front of a low pulley machine that has a barbell or EZ Curl attachment on it.','Move the bench far enough away so that when you bring the handle to the top of your thighs tension is created on the cable due to the weight stack being moved up.','Now hold the handle with both hands, palms up, using a shoulder-width grip.','Step back and sit on the bench with your feet about shoulder width apart, firmly on the floor.','Lean forward and place the forearms on your thighs with the back of your wrists over your knees. This will be your starting position.','Lower the bar as far as possible, while inhaling and keeping a tight grip.','Now curl the bar up as high as possible while contracting the forearms. Tip: Only the wrist should move; not the forearms.','After a second contraction at the top go back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'],'Put a bench in front of a low pulley machine that has a barbell or EZ Curl attachment on it. Move the bench far enough away so that when you bring the handle to the top of your thighs tension is created on the cable due to the weight stack being moved up. Now hold the handle with both hands, palms up, using a shoulder-width grip. Step back and sit on the bench with your feet about shoulder width apart, firmly on the floor. Lean forward and place the forearms on your thighs with the back of your wrists over your knees. This will be your starting position. Lower the bar as far as possible, while inhaling and keeping a tight grip. Now curl the bar up as high as possible while contracting the forearms. Tip: Only the wrist should move; not the forearms. After a second contraction at the top go back to the starting position as you inhale. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Two-Arm_Palms-Up_Low-Pulley_Wrist_Curl/0.jpg','exercisedb',true),('See-Saw_Press_Alternating_Side_Press','See-Saw Press (Alternating Side Press)','hombros',ARRAY['abdominales','tríceps'],'mancuernas','strength',ARRAY['Grab a dumbbell with each hand and stand up erect.','Clean (lift) the dumbbells to the chest/shoulder level and then rotate your wrists so that your palms are facing towards you as if you were getting ready to perform an Arnold Press. This will be your starting position.','Now start extending your left arm overhead as you rotate the wrist so that the palm of your hand faces forward as you go up. Your elbows should come out also as you lift the weight. Simultaneously, you will also be bending from your hip to your opposite side. Tip: If you perform the exercise correctly, is should look as if you are trying to reach for something overhead on the right hand side of your body, but with your left arm. Breathe out as you perform this movement.','Once you reach the top position breathe in. Then, with the weight fully extended overhead and you bent over to your right hand side, begin the movement to the left side.','Repeat for the recommended amount of repetitions.'],'Grab a dumbbell with each hand and stand up erect. Clean (lift) the dumbbells to the chest/shoulder level and then rotate your wrists so that your palms are facing towards you as if you were getting ready to perform an Arnold Press. This will be your starting position. Now start extending your left arm overhead as you rotate the wrist so that the palm of your hand faces forward as you go up. Your elbows should come out also as you lift the weight. Simultaneously, you will also be bending from your hip to your opposite side. Tip: If you perform the exercise correctly, is should look as if you are trying to reach for something overhead on the right hand side of your body, but with your left arm. Breathe out as you perform this movement. Once you reach the top position breathe in. Then, with the weight fully extended overhead and you bent over to your right hand side, begin the movement to the left side. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/See-Saw_Press_Alternating_Side_Press/0.jpg','exercisedb',true),('Shotgun_Row','Shotgun Row','dorsales',ARRAY['bíceps','espalda media'],'cable','strength',ARRAY['Attach a single handle to a low cable.','After selecting the correct weight, stand a couple feet back with a wide-split stance. Your arm should be extended and your shoulder forward. This will be your starting position.','Perform the movement by retracting the shoulder and flexing the elbow. As you pull, supinate the wrist, turning the palm upward as you go.','After a brief pause, return to the starting position.'],'Attach a single handle to a low cable. After selecting the correct weight, stand a couple feet back with a wide-split stance. Your arm should be extended and your shoulder forward. This will be your starting position. Perform the movement by retracting the shoulder and flexing the elbow. As you pull, supinate the wrist, turning the palm upward as you go. After a brief pause, return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shotgun_Row/0.jpg','exercisedb',true),('Shoulder_Circles','Shoulder Circles','hombros',ARRAY['trapecios'],NULL,'stretching',ARRAY['With shoulders relaxed and arms resting loosely at your sides (or in your lap if you''''re seated), gently roll your shoulders forward, up, back, and down.','Reverse direction. You can do this exercise alternating shoulders or both at the same time.'],'With shoulders relaxed and arms resting loosely at your sides (or in your lap if you''re seated), gently roll your shoulders forward, up, back, and down. Reverse direction. You can do this exercise alternating shoulders or both at the same time.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shoulder_Circles/0.jpg','exercisedb',true),('Shoulder_Press_-_With_Bands','Shoulder Press - With Bands','hombros',ARRAY['tríceps'],'bandas elásticas','strength',ARRAY['To begin, stand on an exercise band so that tension begins at arm''''s length. Grasp the handles and lift them so that the hands are at shoulder height at each side.','Rotate the wrists so that the palms of your hands are facing forward. Your elbows should be bent, with the upper arms and forearms in line to the torso. This is your starting position.','As you exhale, lift the handles up until your arms are fully extended overhead.'],'To begin, stand on an exercise band so that tension begins at arm''s length. Grasp the handles and lift them so that the hands are at shoulder height at each side. Rotate the wrists so that the palms of your hands are facing forward. Your elbows should be bent, with the upper arms and forearms in line to the torso. This is your starting position. As you exhale, lift the handles up until your arms are fully extended overhead.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shoulder_Press_-_With_Bands/0.jpg','exercisedb',true),('Shoulder_Raise','Shoulder Raise','hombros',ARRAY['dorsales'],NULL,'stretching',ARRAY['Relax your arms to your sides and raise your shoulders up toward your ears, then back down.'],'Relax your arms to your sides and raise your shoulders up toward your ears, then back down.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shoulder_Raise/0.jpg','exercisedb',true),('Shoulder_Stretch','Shoulder Stretch','hombros',ARRAY[]::text[],NULL,'stretching',ARRAY['Reach your left arm across your body and hold it straight.'],'Reach your left arm across your body and hold it straight.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shoulder_Stretch/0.jpg','exercisedb',true);